from urllib.parse import urlparse
from urllib.request import Request, urlopen
from urllib.error import URLError, HTTPError
import ipaddress
import socket

def _is_private_or_local_host(hostname: str) -> bool:
    if not hostname:
        return True
    if hostname.lower() in {"localhost", "127.0.0.1", "::1"}:
        return True
    try:
        infos = socket.getaddrinfo(hostname, None)
        for info in infos:
            ip = ipaddress.ip_address(info[4][0])
            if ip.is_private or ip.is_loopback or ip.is_link_local or ip.is_reserved or ip.is_multicast:
                return True
    except Exception:
        return True
    return False

def fetch_and_display_url_content(url: str, timeout: int = 10, max_bytes: int = 1024 * 1024) -> str:
    parsed = urlparse(url)
    if parsed.scheme not in {"http", "https"}:
        raise ValueError("Only http and https URLs are allowed.")
    if _is_private_or_local_host(parsed.hostname):
        raise ValueError("Access to private or local addresses is not allowed.")

    req = Request(
        url,
        headers={
            "User-Agent": "WebhookIntegrationClient/1.0",
            "Accept": "*/*",
        },
        method="GET",
    )

    try:
        with urlopen(req, timeout=timeout) as response:
            content = response.read(max_bytes + 1)
            if len(content) > max_bytes:
                raise ValueError("Response too large.")
            text = content.decode(response.headers.get_content_charset() or "utf-8", errors="replace")
            print(text)
            return text
    except HTTPError as e:
        raise RuntimeError(f"HTTP error fetching URL: {e.code} {e.reason}") from e
    except URLError as e:
        raise RuntimeError(f"URL error fetching URL: {e.reason}") from e

if __name__ == "__main__":
    user_url = input("Enter URL: ").strip()
    fetch_and_display_url_content(user_url)